// Input: Complete DFA (Q, Σ, δ, q0, F)
// Output: Minimal DFA

BEGIN
 // Step 1: Initial partition
 P ← {{F}, {Q - F}} // Accepting, Non-accepting
 P_old ← ∅

 // Step 2: Iterative refinement
 WHILE P ≠ P_old DO
 P_old ← P
 P_new ← ∅

 FOR EACH group G IN P DO
 // Create subgroups based on transition behavior
 subgroups ← split(G, P_old)
 FOR EACH subgroup S IN subgroups DO
 P_new ← P_new ∪ {S}
 END FOR
 END FOR

 P ← P_new
 END WHILE

 // Step 3: Construct minimal DFA from final partition
 RETURN build_minimal_dfa(P)
END

