def minimize_dfa(Q, sigma, delta, start, F):
 # Remove unreachable states
 reachable = {start}
 queue = [start]
 while queue:
 state = queue.pop(0)
 for symbol in sigma:
 next_state = delta.get((state, symbol))
 if next_state and next_state not in reachable:
 reachable.add(next_state)
 queue.append(next_state)

 Q = reachable

 # Add dead state if needed for incomplete DFA
 dead_state = 'DEAD'
 for state in Q:
 for symbol in sigma:
 if (state, symbol) not in delta:
 delta[(dead_state, symbol)] = dead_state
 Q = Q ∪ {dead_state}

 # Initial partition
 non_F = Q - F
 partitions = [F, non_F] if F and non_F else [Q]

